  lower_bound: IntervalBoundType,
  upper_bound: IntervalBoundType,
  current_time: Int
) -> Bool {
  // Verificar si la hora actual cae dentro de la ventana
  let lower_ok = case lower_bound {
    Finite(t) -> current_time >= t
    Infinite -> True
  }

  let upper_ok = case upper_bound {
