let price_int = bytearray.to_int_big_endian(price_data)
// price_int == 100000

// Validar un precio en un contrato
if bytearray.to_int_big_endian(oracle_datum) >= min_price {
  // Procesar la transacción
} else {
  // Rechazar
}
