// Define a strategy that only keeps lovelace
fn lovelace_only_strategy(policy: ByteArray, name: ByteArray, amount: Int) -> Option<Int> {
  if policy == "" && name == "" {
    Some(amount)  // Only include lovelace
  } else {
    None          // Discard native tokens
  }
}

let my_value: Value = ...
let lovelace_amounts = flatten_with(my_value, lovelace_only_strategy)
