Here's how you'd write comprehensive unit tests for the `is_valid_amount` function:

```aiken
fn is_valid_amount(amount: Int) -> Bool {
  amount > 0 && amount <= 1000000
}

test valid_amount() {
  is_valid_amount(500) == True
}

test zero_amount_invalid() {
  is_valid_amount(0) == False
}

test negative_amount_invalid() {
  is_valid_amount(-100) == False
}

test max_boundary_valid() {
  is_valid_amount(1000000) == True
}

test over_max_invalid() {
  is_valid_amount(1000001) == False
}
