To generate a test keypair and address, create a file `generate-credentials.ts`:

```typescript
import { MeshWallet } from "@meshsdk/core";
import fs from "node:fs";

async function main() {
  // Generate a new private key (true = testnet)
  const secret_key = MeshWallet.brew(true) as string;
  fs.writeFileSync("me.sk", secret_key);

  // Create wallet from the private key
  const wallet = new MeshWallet({
    networkId: 0, // 0 = testnet (Preview/Preprod), 1 = mainnet
    key: {
      type: "root",
      bech32: secret_key,
    },
  });

  // Export the address
  const address = await wallet.getUnusedAddress();
  fs.writeFileSync("me.addr", address);

  console.log("Private key saved to me.sk");
  console.log("Address saved to me.addr:", address);
}

main().catch(console.error);
```

