- El validador de staking (definido por separado) contendrá la lógica completa: verificación de outputs, cálculos de fees, etc.
- Recuerda registrar el script de staking on-chain antes de usarlo en una transacción real; de lo contrario, el retiro no será válido aunque el hash sea correcto.

Here is how to wire `validate_mint` into your spending validator:

```aiken
use aiken_design_patterns/tx_level_minter.{validate_mint}
use cardano/transaction.{Transaction}
use cardano/assets

// Define your minting policy's redeemer type
type MintRedeemer {
  action: ByteArray
}

validator my_contract(mint_script_hash: PolicyId) {
  spend(
    _datum: Option<Data>,
    _redeemer: Data,
    _own_ref: OutputReference,
    tx: Transaction,
  ) {
    validate_mint(
      mint_script_hash,          // the policy ID of your minting script
      tx.mint,                   // the Value from the transaction's mint field
      tx.redeemers,              // all redeemers in the transaction
      0,                         // positional index of the mint redeemer (first = 0)
      fn(rdmr, tokens) {
        // rdmr is the raw Data of the minting redeemer
        // tokens is a Dict<AssetName, Int> of what's being minted/burned
        expect mint_rdmr: MintRedeemer = rdmr
        dict.size(tokens) > 0 && mint_rdmr.action == "execute"
      },
    )
  }

  // Your minting policy holds the real logic
  mint(redeemer: MintRedeemer, policy_id: PolicyId, tx: Transaction) {
    // ... full validation here ...
    True
  }
}
```

**Key points:**
- `mint_redeemer_index` is the **positional index** of the `Mint` purpose entry in `tx.redeemers`. Redeemers are ordered, so you must know or compute this index ahead of time (typically determined off-chain).
- The `mint_validator` callback receives the raw redeemer `Data` and a `Dict<AssetName, Int>` of minted/burned tokens for that policy.
- Use `validate_mint_minimal` instead if you only need to confirm the policy is active, without inspecting the redeemer.

