use aiken/collection/list
use cardano/assets
use cardano/transaction

pub type Datum {
  oracle_ref: transaction.OutputReference,
}

validator price_check {
  spend(datum: Option<Datum>, _redeemer, _own_ref, self) {
    expect Some(Datum { oracle_ref }) = datum
    expect Some(oracle_input) =
      transaction.find_input(self.reference_inputs, oracle_ref)

    expect transaction.InlineDatum(raw_datum) = oracle_input.output.datum
    expect min_lovelace: Int = raw_datum

    let total_out =
      list.foldl(
        self.outputs,
        0,
        fn(output, acc) { acc + assets.lovelace_of(output.value) },
      )

    total_out >= min_lovelace
  }
}

