use aiken/collection/list
use cardano/transaction

pub type Datum {
  counter: Int,
}

validator increment_counter(script_hash) {
  spend(datum: Option<Datum>, _redeemer, _own_ref, self) {
    expect Some(Datum { counter }) = datum

    let continuing =
      transaction.find_script_outputs(self.outputs, script_hash)

    expect Some(cont_output) = list.head(continuing)
    expect transaction.InlineDatum(raw) = cont_output.datum
    expect Datum { counter: new_counter } = raw

    new_counter == counter + 1
  }
}

