use aiken/collection/dict
use cardano/assets

validator capped_mint {
  mint(_redeemer, policy_id, self) {
    expect pairs =
      self.mint
        |> assets.tokens(policy_id)
        |> dict.to_pairs()

    let total =
      list.foldl(
        pairs,
        0,
        fn(pair, acc) {
          let Pair(_asset_name, qty) = pair
          acc + qty
        },
      )

    total <= 1000
  }
}
